 39→// TeamIDForUser looks up the team_id for a given user_id.
 40→func (s *Service) TeamIDForUser(ctx context.Context, userID string) (string, error) {
 41→	var teamID string
 42→	err := s.pool.QueryRow(ctx,
 43→		`SELECT team_id FROM subscription.team_member WHERE user_id = $1`, userID,
 44→	).Scan(&teamID)
 45→	if err != nil {
 46→		return "", fmt.Errorf("savedsearch: team for user %s: %w", userID, err)
 47→	}
 48→	return teamID, nil
 49→}
