 51→// List returns all saved searches for the given team, most recently updated first.
 52→func (s *Service) List(ctx context.Context, teamID string) ([]SavedSearch, error) {
 53→	rows, err := s.pool.Query(ctx, `
 54→		SELECT id, name, hash, query, created, updated
 55→		FROM ugc.saved_search
 56→		WHERE team_id = $1
 57→		ORDER BY updated DESC`, teamID)
 58→	if err != nil {
 59→		return nil, fmt.Errorf("savedsearch: list for team %s: %w", teamID, err)
 60→	}
 61→	defer rows.Close()
 62→
 63→	var results []SavedSearch
 64→	for rows.Next() {
 65→		var ss SavedSearch
 66→		var raw []byte
 67→		if err := rows.Scan(&ss.ID, &ss.Name, &ss.Hash, &raw, &ss.Created, &ss.Updated); err != nil {
 68→			return nil, fmt.Errorf("savedsearch: scan: %w", err)
 69→		}
 70→		var q queryJSON
 71→		if err := json.Unmarshal(raw, &q); err != nil {
 72→			return nil, fmt.Errorf("savedsearch: unmarshal query for %s: %w", ss.ID, err)
 73→		}
 74→		ss.SearchState = q.S
 75→		results = append(results, ss)
 76→	}
 77→	if err := rows.Err(); err != nil {
 78→		return nil, fmt.Errorf("savedsearch: rows: %w", err)
 79→	}
 80→	return results, nil
 81→}
 82→
 83→// Save creates a new saved search and returns it.
 84→func (s *Service) Save(ctx context.Context, teamID, name, searchState string) (*SavedSearch, error) {
 85→	hash := computeHash(searchState)
 86→	q := queryJSON{S: searchState}
 87→	data, err := json.Marshal(q)
 88→	if err != nil {
 89→		return nil, fmt.Errorf("savedsearch: marshal: %w", err)
 90→	}
 91→
 92→	var ss SavedSearch
 93→	err = s.pool.QueryRow(ctx, `
 94→		INSERT INTO ugc.saved_search (id, team_id, name, hash, query)
 95→		VALUES (gen_random_uuid()::varchar(62), $1, $2, $3, $4)
 96→		RETURNING id, name, hash, created, updated`,
 97→		teamID, name, hash, data,
 98→	).Scan(&ss.ID, &ss.Name, &ss.Hash, &ss.Created, &ss.Updated)
 99→	if err != nil {
100→		return nil, fmt.Errorf("savedsearch: save for team %s: %w", teamID, err)
101→	}
102→	ss.SearchState = searchState
103→	return &ss, nil
104→}
105→
106→// Delete removes a saved search by ID, scoped to the given team for authorization.
107→// Returns an error if the row does not exist or belongs to a different team.
108→func (s *Service) Delete(ctx context.Context, teamID, id string) error {
109→	tag, err := s.pool.Exec(ctx, `
110→		DELETE FROM ugc.saved_search
111→		WHERE id = $1 AND team_id = $2`, id, teamID)
112→	if err != nil {
113→		return fmt.Errorf("savedsearch: delete %s: %w", id, err)
114→	}
115→	if tag.RowsAffected() == 0 {
116→		return fmt.Errorf("savedsearch: delete %s: not found or not owned", id)
117→	}
118→	return nil
119→}
120→
121→// computeHash returns the SHA-256 hex digest of a search state string.
122→func computeHash(searchState string) string {
123→	h := sha256.Sum256([]byte(searchState))
124→	return hex.EncodeToString(h[:])
125→}
